effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);


void main() {
    if( acPass==0 ) {

        discard;
    } else {
        vec4 baseColor =  texture2DCv(hblur.texture, acScreenNorm.st);
        vec4 mainColor = texture2DCv(inputImg.texture,acScreenNorm.st) * fill;
        float luma = dot(baseColor.rgb, luminanceWeighting);
        float adjThreshold = threshold * (1.0 + radius) - radius;
        if(luma >= adjThreshold && luma <= adjThreshold + radius)
        {
            float halfRadius = radius*0.5;
            float linearPos = abs((luma - adjThreshold - halfRadius)/halfRadius);
            vec4 glow = pow(mix(baseColor, fillColor*luma, blend*0.99), vec4(power) * pow(linearPos, 2.0));
            mainColor = mix(mainColor, baseColor + glow, alpha);
        }
        gl_FragColor = mainColor;
    }
}
